import React from "react";
import "./BatchDashboard.css";

function BatchDashboard({ dashboardData }) {
  if (!dashboardData || !dashboardData.batchResult) {
    return (
      <div className="batch-dashboard">
        <div className="no-data-message">
          <h3>No Batch Analysis Results Available</h3>
          <p>Please run a batch analysis first from the Batch Processing section.</p>
        </div>
      </div>
    );
  }

  const { batchResult } = dashboardData;
  const { dataset_info, risk_analysis, customer_segmentation, feature_analysis, sample_predictions, data_source } = batchResult;

  // Calculate percentages for risk distribution
  const totalCustomers = dataset_info.total_customers;
  const riskDistribution = risk_analysis.risk_distribution || {};

  // Function to download full report from backend
  const downloadFullReport = async () => {
    try {
      // This would need the original file - in a real implementation, you'd store the file
      // or send it again. For now, we'll show a message.
      alert("Full dataset download requires re-uploading the CSV file. Please use the batch processing page to download the complete report.");
      
      // In a real implementation, you would:
      // 1. Store the original file or send it again to the backend
      // 2. Call the download endpoint: /api/batch/download-report
      // 3. Handle the file download

    } catch (error) {
      console.error('Error generating report:', error);
      alert('Error generating report. Please try again.');
    }
  };

  // Function to download sample report
  const downloadSampleReport = () => {
    if (!sample_predictions || sample_predictions.length === 0) {
      alert("No prediction data available for download.");
      return;
    }

    // Create CSV content with sample data
    const headers = [
      'Customer_ID', 
      'Tenure', 'OrderCount', 'CashbackAmount', 'DaySinceLastOrder', 
      'HourSpendOnApp', 'SatisfactionScore', 'WarehouseToHome',
      'Churn_Probability_Percent', 'Risk_Level', 'Predicted_Churn',
      'Retention_Recommendation'
    ];

    let csvContent = headers.join(',') + '\n';

    sample_predictions.forEach((customer, index) => {
      const riskLevel = customer.Risk_Level || 'Unknown';
      const churnProb = customer.Churn_Probability ? (customer.Churn_Probability * 100).toFixed(2) : '0.00';
      
      // Determine retention recommendation based on risk level
      let recommendation = '';
      if (riskLevel.includes('High')) {
        recommendation = 'Immediate personalized outreach + Exclusive offers + Executive escalation';
      } else if (riskLevel.includes('Moderate')) {
        recommendation = 'Proactive engagement campaigns + Loyalty program enrollment + Personalized recommendations';
      } else {
        recommendation = 'Maintain regular communication + Upsell opportunities + Referral program promotion';
      }

      const row = [
        `CUST_${index + 1}`,
        customer.Tenure || '',
        customer.OrderCount || '',
        customer.CashbackAmount || '',
        customer.DaySinceLastOrder || '',
        customer.HourSpendOnApp || '',
        customer.SatisfactionScore || '',
        customer.WarehouseToHome || '',
        churnProb + '%',
        riskLevel,
        customer.Predicted_Churn ? 'Yes' : 'No',
        `"${recommendation}"` // Wrap in quotes for CSV
      ];

      csvContent += row.join(',') + '\n';
    });

    // Add summary section
    csvContent += '\n\nSUMMARY\n';
    csvContent += `Total Customers Analyzed,${totalCustomers}\n`;
    csvContent += `Average Churn Probability,${(risk_analysis.average_probability * 100).toFixed(2)}%\n`;
    csvContent += `Overall Churn Rate,${(risk_analysis.churn_rate * 100).toFixed(2)}%\n`;
    csvContent += `High-Risk Customers,${customer_segmentation.high_risk_customers}\n`;
    csvContent += `Moderate-Risk Customers,${riskDistribution['P2: Moderate Risk (31-70%)'] || 0}\n`;
    csvContent += `Low-Risk Customers,${riskDistribution['P3: Low Risk (<=30%)'] || 0}\n`;
    csvContent += `Data Source,${data_source}\n`;
    csvContent += `Analysis Date,${new Date().toLocaleDateString()}\n`;
    csvContent += `Potential Revenue Loss,₹${(customer_segmentation.potential_revenue_loss || 0).toLocaleString()}\n`;

    // Create and trigger download
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    
    link.setAttribute('href', url);
    link.setAttribute('download', `churn_analysis_sample_report_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="batch-dashboard">
      <div className="dashboard-header">
        <h2>📊 Batch Analysis Dashboard</h2>
        <div className="header-actions">
          <button 
            className="download-report-btn"
            onClick={downloadSampleReport}
            title="Download sample report with predictions"
          >
            <span className="btn-icon">📥</span>
            Download Report
          </button>
        </div>
      </div>

      {/* Dataset Overview */}
      <div className="section-card dataset-overview">
        <h3>📁 Dataset Overview</h3>
        <div className="dataset-stats-grid">
          <div className="stat-card">
            <div className="stat-value">{dataset_info.total_customers}</div>
            <div className="stat-label">Total Customers</div>
          </div>
          <div className="stat-card">
            <div className="stat-value">{dataset_info.total_features}</div>
            <div className="stat-label">Features Analyzed</div>
          </div>
          <div className="stat-card">
            <div className="stat-value">{dataset_info.dataset_size_kb.toFixed(1)} KB</div>
            <div className="stat-label">Dataset Size</div>
          </div>
          <div className="stat-card">
            <div className="stat-value">{risk_analysis.total_predicted_churn}</div>
            <div className="stat-label">Predicted Churn</div>
          </div>
        </div>
        
        <div className="data-source-info">
          <span className="source-label">Data Source:</span>
          <span className="source-value">{data_source === "demo" ? "Demo Data" : "Uploaded CSV"}</span>
        </div>
      </div>

      {/* Risk Analysis */}
      <div className="section-card risk-analysis">
        <h3>⚠️ Risk Analysis Summary</h3>
        <div className="risk-metrics-grid">
          <div className="risk-metric">
            <div className="metric-value">{risk_analysis.average_probability?.toFixed(3) || '0.000'}</div>
            <div className="metric-label">Average Churn Probability</div>
          </div>
          <div className="risk-metric">
            <div className="metric-value">{((risk_analysis.churn_rate || 0) * 100).toFixed(1)}%</div>
            <div className="metric-label">Overall Churn Rate</div>
          </div>
          <div className="risk-metric">
            <div className="metric-value">{customer_segmentation.high_risk_customers || 0}</div>
            <div className="metric-label">High-Risk Customers</div>
          </div>
          <div className="risk-metric">
            <div className="metric-value">₹{(customer_segmentation.potential_revenue_loss || 0).toLocaleString()}</div>
            <div className="metric-label">Potential Revenue Loss</div>
          </div>
        </div>

        {/* Risk Distribution */}
        <div className="risk-distribution">
          <h4>Risk Level Distribution</h4>
          <div className="distribution-bars">
            {Object.entries(riskDistribution).map(([riskLevel, count]) => {
              const percentage = totalCustomers > 0 ? (count / totalCustomers * 100).toFixed(1) : 0;
              let barColor = "";
              
              if (riskLevel.includes("High")) barColor = "high-risk";
              else if (riskLevel.includes("Moderate")) barColor = "medium-risk";
              else barColor = "low-risk";

              return (
                <div key={riskLevel} className="distribution-item">
                  <div className="risk-label">{riskLevel}</div>
                  <div className="bar-container">
                    <div 
                      className={`risk-bar ${barColor}`}
                      style={{ width: `${percentage}%` }}
                    >
                      <span className="bar-count">{count} customers</span>
                    </div>
                  </div>
                  <div className="risk-percentage">{percentage}%</div>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* Feature Analysis */}
      {feature_analysis && Object.keys(feature_analysis).length > 0 && (
        <div className="section-card feature-analysis">
          <h3>🔍 High-Risk Customer Profile</h3>
          <div className="feature-grid">
            {Object.entries(feature_analysis).slice(0, 6).map(([feature, stats]) => (
              <div key={feature} className="feature-card">
                <div className="feature-name">{feature}</div>
                <div className="feature-stats">
                  <div className="stat">
                    <span className="stat-label">Avg:</span>
                    <span className="stat-value">{(stats.mean || 0).toFixed(2)}</span>
                  </div>
                  <div className="stat">
                    <span className="stat-label">Med:</span>
                    <span className="stat-value">{(stats.median || 0).toFixed(2)}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Sample Predictions */}
      <div className="section-card sample-predictions">
        <div className="predictions-header">
          <h3>📋 Sample Predictions</h3>
          <span className="sample-info">Showing first 10 customers</span>
        </div>
        <div className="predictions-table">
          <table>
            <thead>
              <tr>
                <th>Customer</th>
                <th>Churn Probability</th>
                <th>Risk Level</th>
                <th>Prediction</th>
                <th>Recommendation</th>
              </tr>
            </thead>
            <tbody>
              {sample_predictions && sample_predictions.slice(0, 10).map((customer, index) => {
                const riskLevel = customer.Risk_Level || 'Unknown';
                let recommendation = '';
                
                if (riskLevel.includes('High')) {
                  recommendation = 'Immediate outreach + Exclusive offers';
                } else if (riskLevel.includes('Moderate')) {
                  recommendation = 'Proactive engagement + Loyalty program';
                } else {
                  recommendation = 'Maintain relationship + Upsell opportunities';
                }

                return (
                  <tr key={index}>
                    <td>Customer {index + 1}</td>
                    <td>
                      <div className="probability-bar">
                        <div 
                          className="probability-fill"
                          style={{ width: `${(customer.Churn_Probability || 0) * 100}%` }}
                        ></div>
                        <span className="probability-text">
                          {((customer.Churn_Probability || 0) * 100).toFixed(1)}%
                        </span>
                      </div>
                    </td>
                    <td>
                      <span className={`risk-badge ${riskLevel.toLowerCase().replace(' ', '-')}`}>
                        {riskLevel}
                      </span>
                    </td>
                    <td>
                      <span className={`prediction ${customer.Predicted_Churn ? 'churn' : 'no-churn'}`}>
                        {customer.Predicted_Churn ? "🚨 Churn" : "✅ Retain"}
                      </span>
                    </td>
                    <td>
                      <span className="recommendation-text">{recommendation}</span>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Report Download Section */}
      <div className="section-card download-section">
        <h3>📥 Download Reports</h3>
        <div className="download-options">
          <div className="download-option">
            <h4>📊 Sample Analysis Report</h4>
            <p>Download the first 10 customer predictions with churn probabilities, risk levels, and retention recommendations in CSV format.</p>
            <button className="download-btn primary" onClick={downloadSampleReport}>
              <span className="btn-icon">📥</span>
              Download Sample Report (CSV)
            </button>
          </div>
        </div>
        
        <div className="report-features">
          <h5>Report Includes:</h5>
          <ul>
            <li>✅ Original customer data features</li>
            <li>✅ Churn probability percentages</li>
            <li>✅ Risk level classification (Low/Medium/High)</li>
            <li>✅ Churn prediction (Yes/No)</li>
            <li>✅ Personalized retention recommendations</li>
            <li>✅ Summary statistics and insights</li>
          </ul>
        </div>
        
        <div className="download-note">
          <p><strong>Note:</strong> The sample report contains the first 10 customers from your analysis. For the complete dataset with all customers, please re-upload your CSV file and use the download option on the batch processing page.</p>
        </div>
      </div>
    </div>
  );
}

export default BatchDashboard;
